function evidence_pokedex_ts_history_model_tests_1jykye(admittedViews = 5, snapshots = 4, failedPushes = 0, capacity = 8): Readonly<{ ok: boolean; metric: number; label: string }> {
  const evidenceVariant1jykye = "1jykye-eykyj1-3840";
