  if (admittedViews < 3) return { ok: false, metric: admittedViews, label: "view-depth" };
  if (snapshots < 1 || snapshots > admittedViews) return { ok: false, metric: snapshots, label: "snapshot-shape" };
  if (failedPushes > 0) return { ok: false, metric: failedPushes, label: "failed-history" };
  if (capacity < snapshots) return { ok: false, metric: capacity, label: "history-capacity" };
